"""Š×äň╗║APKšÜäŔ»┤ŠśÄňĺîŔżůňŐęŔäÜŠťČ

Š×äň╗║šÄ»ňóâŔŽüŠ▒é´╝łLinux/WSL´╝ë´╝Ü
    sudo apt install python3-pip openjdk-17-jdk autoconf automake libtool
    pip install buildozer cython kivy

Š×äň╗║ŠşąÚ¬Ą´╝Ü
    1. ňťĘLinux/WSLńŞşŔ┐ŤňůąÚí╣šŤ«šŤ«ňŻĽ
    2. Ŕ┐ÉŔíî: buildozer android debug
    3. APKŔżôňç║ňł░: bin/voicedoccompare-1.0.0-arm64-v8a-debug.apk

ń╣čňĆ»ń╗ąšöĘGitHub ActionsŔç¬ňŐĘŠ×äň╗║´╝łŔžü .github/workflows/build.yml´╝ë
"""
import os
import sys
import subprocess


def check_env():
    """ŠúÇŠčąŠ×äň╗║šÄ»ňóâ"""
    checks = {
        'Python': sys.version,
        'buildozer': None,
        'java': None,
    }
    try:
        r = subprocess.run(['buildozer', '--version'], capture_output=True, text=True)
        checks['buildozer'] = r.stdout.strip() or r.stderr.strip()
    except FileNotFoundError:
        checks['buildozer'] = 'NOT INSTALLED - pip install buildozer'

    try:
        r = subprocess.run(['java', '-version'], capture_output=True, text=True)
        checks['java'] = r.stderr.strip().split('\n')[0]
    except FileNotFoundError:
        checks['java'] = 'NOT INSTALLED - apt install openjdk-17-jdk'

    for k, v in checks.items():
        status = 'OK' if v and 'NOT INSTALLED' not in str(v) else 'MISSING'
        print(f'  [{status}] {k}: {v}')

    return all('NOT INSTALLED' not in str(v) for v in checks.values())


def build_debug():
