"""ŠáŞň┐âň»╣Š»öš«ŚŠ│Ľ - ň«îňůĘšž╗ŠĄŹŔç¬ŠíîÚŁóšëł compare.py´╝îÚÇéÚůŹAndroid"""
import re
from difflib import SequenceMatcher
from functools import lru_cache
from typing import List, Dict

FILLER_WORDS = {'ňŚ»', 'ňĹâ', 'ňĽŐ', 'ňôŽ', 'ňĹó', 'ňÉž', 'ňśŤ', 'ňôł', 'ňÖó', 'Ŕ»Â',
                'ÚéúńŞ¬', 'ň░▒Šś»', 'ň░▒Šś»Ŕ»┤', 'šäÂňÉÄ', 'ň»╣ňÉž', 'ň»╣šÜä', 'Ŕ┐ÖńŞ¬',
                'Úéú', 'ŠëÇń╗ą', 'ńŻćŠś»', 'ńŞŹŔ┐ç', 'ňůÂň«×', 'ňĆŹŠşú', 'ňąŻšÜä'}

CN_NUMBERS_READING = {
    '0': 'ÚŤÂ', '1': 'ńŞÇ', '2': 'ń║î', '3': 'ńŞë', '4': 'ňŤŤ',
    '5': 'ń║ö', '6': 'ňůş', '7': 'ńŞâ', '8': 'ňůź', '9': 'ń╣Ł'
}

# Úóäš╝ľŔ»ĹŠşúňłÖŔíĘŔżżň╝Ć
_RE_PUNCT = re.compile(r'[´╝îŃÇé´╝ü´╝č´╝Ť´╝ÜŃÇü\u201c\u201d\u2018\u2019´╝ł´╝ëŃÇÉŃÇĹŃÇŐŃÇőÔÇŽÔÇö┬Ě\s,.!?;:\'"()\[\]{}\-]')

_SENTENCE_END_PUNCT = set('ŃÇé´╝ü´╝č.!?\n')

# jiebaňłćŔ»ŹňÖĘšŐÂŠÇü
_jieba_initialized = False
_jieba_available = None


def _ensure_jieba():
    """ší«ń┐ŁjiebaňĆ»šöĘň╣ÂňłŁňžőňîľ"""
    global _jieba_initialized, _jieba_available
    if _jieba_available is None:
        try:
            import jieba
            _jieba_available = True
        except ImportError:
            _jieba_available = False
    if _jieba_available and not _jieba_initialized:
        import jieba
        jieba.initialize()
        _jieba_initialized = True
    return _jieba_available


# Šő╝Úč│š╝ôňşś
@lru_cache(maxsize=10000)
def _get_char_pinyin(char: str):
    """ŔÄĚňĆľňŹĽńŞ¬ňşŚšČŽšÜäŠő╝Úč│´╝łňŞŽš╝ôňşś´╝ë"""
    if not char:
        return []
    try:
        from pypinyin import pinyin, Style
        return pinyin(char, style=Style.TONE3, neutral_tone_with_five=True)[0]
    except ImportError:
        return [char]


def _is_punct(ch: str) -> bool:
    if len(ch) == 1:
        if ch in '.,!?;:\'"()[]{}-\n\r\t ':
            return True
    return _RE_PUNCT.match(ch) is not None


def _normalize(text):
    return _RE_PUNCT.sub('', text)


def _arabic_to_chinese_simple(num_str, is_year=False):
    if not num_str or not num_str.isdigit():
        return num_str
    if is_year:
        return ''.join(CN_NUMBERS_READING.get(d, d) for d in num_str)
    try:
        num = int(num_str)
        if num < 10:
            return CN_NUMBERS_READING[num_str]
        elif num < 20:
            return 'ňŹü' + (CN_NUMBERS_READING[num_str[1]] if num_str[1] != '0' else '')
        elif num < 100:
            tens = num // 10
            ones = num % 10
            result = CN_NUMBERS_READING[str(tens)] + 'ňŹü' if tens != 1 else 'ňŹü'
            if ones > 0:
                result += CN_NUMBERS_READING[str(ones)]
            return result
        elif num < 1000:
            hundreds = num // 100
            remainder = num % 100
            result = CN_NUMBERS_READING[str(hundreds)] + 'šÖż'
            if remainder > 0:
                if remainder < 10:
                    result += 'ÚŤÂ' + CN_NUMBERS_READING[str(remainder)]
                elif remainder < 20:
                    result += 'ńŞÇňŹü'
                    if remainder > 10:
                        result += CN_NUMBERS_READING[str(remainder % 10)]
                else:
                    result += _arabic_to_chinese_simple(str(remainder))
            return result
        elif num < 10000:
            thousands = num // 1000
            remainder = num % 1000
            result = CN_NUMBERS_READING[str(thousands)] + 'ňŹâ'
            if remainder > 0 and remainder < 100:
                result += 'ÚŤÂ' + _arabic_to_chinese_simple(str(remainder))
            elif remainder >= 100:
                result += _arabic_to_chinese_simple(str(remainder))
            return result
        elif num < 100000000:
            wan = num // 10000
            remainder = num % 10000
            result = _arabic_to_chinese_simple(str(wan)) + 'ńŞç'
            if remainder > 0 and remainder < 1000:
                result += 'ÚŤÂ' + _arabic_to_chinese_simple(str(remainder))
            elif remainder >= 1000:
                result += _arabic_to_chinese_simple(str(remainder))
            return result
        else:
            yi = num // 100000000
            remainder = num % 100000000
            result = _arabic_to_chinese_simple(str(yi)) + 'ń║┐'
            if remainder > 0:
                result += _arabic_to_chinese_simple(str(remainder))
            return result
    except:
        return num_str


def _normalize_number_reading(text):
    result = text
    # 1. ň╣┤ń╗Ż
    def convert_year(match):
        year = match.group(1)
        return ''.join(CN_NUMBERS_READING.get(d, d) for d in year) + 'ň╣┤'
    result = re.sub(r'(\d{4})ň╣┤', convert_year, result)

    # 2. šÖżňłćŠ»öŔîâňŤ┤
    def convert_percent_range(match):
        num1 = match.group(1)
        num2 = match.group(2)
        return 'šÖżňłćń╣ő' + _arabic_to_chinese_simple(num1) + 'ňł░šÖżňłćń╣ő' + _arabic_to_chinese_simple(num2)
    result = re.sub(r'(\d+)%-(\d+)%', convert_percent_range, result)

    # 3. ŔîâňŤ┤ŔíĘŔżżň╝Ć
    def convert_range(match):
        num1 = match.group(1)
        num2 = match.group(2)
        suffix = match.group(3) if match.group(3) else ''
        return _arabic_to_chinese_simple(num1) + 'ňł░' + _arabic_to_chinese_simple(num2) + suffix
    result = re.sub(r'(\d+)-(\d+)(ň╣┤|Šťł|ŠŚą|ňůâ|šżÄňůâ|ń║┐|ńŞç|)?', convert_range, result)

    # 4. šÖżňłćŠ»ö
    def convert_percent(match):
        num = match.group(1)
        return 'šÖżňłćń╣ő' + _arabic_to_chinese_simple(num)
    result = re.sub(r'(\d+)%', convert_percent, result)

    # 5. ňŞŽňŹĽńŻŹŠĽ░ňşŚ
    def convert_with_unit(match):
        num = match.group(1)
        unit = match.group(2)
        return _arabic_to_chinese_simple(num) + unit
    result = re.sub(r'(\d+)([ń║┐ńŞçňŹâšÖżňůâňŁŚšżÄ])', convert_with_unit, result)

    # 6. ňëęńŻÖš║»ŠĽ░ňşŚ
    def convert_number(match):
        num = match.group(1)
        return _arabic_to_chinese_simple(num)
    result = re.sub(r'\b(\d+)\b', convert_number, result)

    result = re.sub(r'\s+', '', result)
    return result


def _same_pinyin(a: str, b: str) -> bool:
    if not a or not b:
        return False
    a_normalized = _normalize_number_reading(a)
    b_normalized = _normalize_number_reading(b)
    a_clean = _normalize(a_normalized)
    b_clean = _normalize(b_normalized)
    if not a_clean or not b_clean:
        return False
    # šŤ┤ŠÄąňşŚšČŽńŞ▓Š»öŔżâ
    if a_clean == b_clean:
        return True
    # Ŕő▒Ŕ»şňĄžň░ĆňćÖ
    if a_clean.lower() == b_clean.lower():
        return True

    pa = [_get_char_pinyin(c) for c in a_clean]
    pb = [_get_char_pinyin(c) for c in b_clean]

    if len(pa) == len(pb):
        return pa == pb

    # ÚĽ┐ň║ŽńŞŹňÉîŠŚÂŠúÇŠčąňşÉň║ĆňłŚŠő╝Úč│
    if len(pa) < len(pb):
        return _is_subsequence_pinyin(pa, pb)
    else:
        return _is_subsequence_pinyin(pb, pa)


def _is_subsequence_pinyin(shorter, longer):
    if not shorter:
        return True
    if not longer:
        return False
    from collections import Counter
    shorter_strs = [''.join(p) if isinstance(p, list) else str(p) for p in shorter]
    longer_strs = [''.join(p) if isinstance(p, list) else str(p) for p in longer]
    shorter_counter = Counter(shorter_strs)
    longer_counter = Counter(longer_strs)
    for py, count in shorter_counter.items():
        if longer_counter.get(py, 0) < count:
            return False
    return True


def _punct_only_diff(a, b):
    na, nb = _normalize(a), _normalize(b)
    if na != nb:
        return False
    return _sentence_breaks_match(a, b)


def _get_sentence_breaks(text):
    breaks = []
    char_idx = 0
    for ch in text:
        if _is_punct(ch):
            if ch in _SENTENCE_END_PUNCT:
                breaks.append(char_idx)
        else:
            char_idx += 1
    return breaks


def _sentence_breaks_match(doc_text, audio_text):
    doc_breaks = _get_sentence_breaks(doc_text)
    audio_breaks = _get_sentence_breaks(audio_text)
    if not doc_breaks and not audio_breaks:
        return True
    if not doc_breaks or not audio_breaks:
        return len(doc_breaks) == len(audio_breaks)
    return doc_breaks == audio_breaks


def _segment(text: str) -> List[str]:
    if _ensure_jieba():
        import jieba
        return [w for w in jieba.cut(text) if w.strip()]
    return [c for c in text if c.strip()]


def _find_paragraph(doc_paragraphs, doc_text_norm, word_pos, doc_words):
    char_offset = 0
    for i, w in enumerate(doc_words):
        if i == word_pos:
            break
        char_offset += len(w)
    running = 0
    for idx, p in enumerate(doc_paragraphs):
        plen = len(_normalize(p))
        if running + plen > char_offset:
            return idx
        running += plen
    return len(doc_paragraphs) - 1


def compare_texts(audio_text, doc_text, word_timestamps=None, confidence_threshold=0.0):
    """ŠáŞň┐âň»╣Š»öš«ŚŠ│Ľ´╝ÜjiebaňłćŔ»Ź + SequenceMatcher + Šő╝Úč│ňÉîÚč│ňşŚŔ»ćňłź
    ň«îňůĘšž╗ŠĄŹŔç¬ŠíîÚŁóšëłŃÇé
    """
    doc_paragraphs = [p.strip() for p in doc_text.split('\n') if p.strip()]

    audio_norm = _normalize(audio_text)
    doc_norm = _normalize(doc_text)
    audio_words = _segment(audio_norm)
    doc_words = _segment(doc_norm)

    # ŠŚÂÚŚ┤Šł│Šśáň░ä
    ts_map = {}
    if word_timestamps:
        offset = 0
        for wt in word_timestamps:
            w_normalized = _normalize(wt['word'])
            for i in range(len(w_normalized)):
                ts_map[offset + i] = {'start': wt['start'], 'end': wt['end'], 'confidence': wt.get('confidence', 1.0)}
            offset += len(w_normalized)

    # ň║ĆňłŚŠ»öň»╣
    matcher = SequenceMatcher(None, doc_words, audio_words)
    raw_diffs = []

    audio_char_offsets = []
    off = 0
    for w in audio_words:
        audio_char_offsets.append(off)
        off += len(w)

    for tag, i1, i2, j1, j2 in matcher.get_opcodes():
        if tag == 'equal':
            continue

        doc_fragment = ''.join(doc_words[i1:i2])
        audio_fragment = ''.join(audio_words[j1:j2])

        # Ŕ┐çŠ╗ĄňíźňůůŔ»Ź
        if tag == 'insert' and audio_fragment in FILLER_WORDS:
            continue
        if tag == 'delete' and doc_fragment in FILLER_WORDS:
            continue
        if tag == 'replace':
            if doc_fragment in FILLER_WORDS and audio_fragment in FILLER_WORDS:
                continue
            if _same_pinyin(doc_fragment, audio_fragment):
                continue
            if _punct_only_diff(doc_fragment, audio_fragment):
                continue

        # ŔĚ│Ŕ┐çš║»šę║šÖŻ/Šáçšé╣ňĚ«ň╝é
        if not doc_fragment.strip() and not audio_fragment.strip():
            continue
        if all(_is_punct(c) or not c.strip() for c in doc_fragment) and all(_is_punct(c) or not c.strip() for c in audio_fragment):
            continue

        pos = _find_paragraph(doc_paragraphs, doc_norm, i1, doc_words)

        # ŠŚÂÚŚ┤Šł│
        ts_start = ts_end = None
        confidence = 1.0
        if ts_map and j1 < len(audio_char_offsets):
            char_off = audio_char_offsets[j1]
            if char_off in ts_map:
                ts_start = ts_map[char_off]['start']
                confidence = ts_map[char_off]['confidence']
            if j2 > 0 and j2 - 1 < len(audio_char_offsets):
                end_off = audio_char_offsets[j2 - 1]
                if end_off in ts_map:
                    ts_end = ts_map[end_off]['end']

        diff_entry = {
            'docText': doc_fragment,
            'audioText': audio_fragment,
            'type': 'mismatch' if tag == 'replace' else ('missing_in_audio' if tag == 'delete' else 'extra_in_audio'),
            'position': pos,
            'confidence': confidence,
            'uncertain': confidence < confidence_threshold if confidence_threshold > 0 else False,
        }
        if ts_start is not None:
            diff_entry['time_start'] = ts_start
        if ts_end is not None:
            diff_entry['time_end'] = ts_end
        raw_diffs.append(diff_entry)

    n_mismatch = sum(1 for d in raw_diffs if d['type'] == 'mismatch')
    n_missing = sum(1 for d in raw_diffs if d['type'] == 'missing_in_audio')
    n_extra = sum(1 for d in raw_diffs if d['type'] == 'extra_in_audio')

    # ŠľşňĆąň»╣ÚŻÉŠúÇŠčą
    break_ok = _sentence_breaks_match(doc_text, audio_text)
    break_note = '' if break_ok else '\nŔ»şÚč│ŠľşňĆąńŻŹšŻ«ńŞÄňÄčŠľçńŞŹńŞÇŔç┤'

    # ňçćší«šÄçŔ«íš«Ś
    total = max(len(doc_norm), 1)
    diff_chars = sum(max(len(d['docText']), len(d['audioText'])) for d in raw_diffs)
    accuracy = max(0, (1 - diff_chars / total) * 100)

    summary = f'ňů▒{len(raw_diffs)}ňĄäňĚ«ň╝é´╝Ü{n_mismatch}ňĄäŔ»»Ŕ»╗´╝î{n_missing}ňĄäŠ╝ĆŔ»╗´╝î{n_extra}ňĄäňĄÜŔ»╗{break_note}\nňşŚňçćší«šÄç {accuracy:.1f}%'

    return {
        'diffs': raw_diffs,
        'summary': summary,
        'accuracy': accuracy,
        'n_mismatch': n_mismatch,
        'n_missing': n_missing,
        'n_extra': n_extra,
    }

"""Androidšź»Pythonň╝ĽŠôÄ - ňĄÜASRň╝ĽŠôÄ + ŠľçŠťČň»╣Š»ö
   ASRň╝ĽŠôÄ´╝ÜSherpa-ONNX(Javańżž) / šÖżň║Ž(ňćůšŻ«) / Groq Whisper / OpenAI Whisper / FunASR(ň▒ÇňččšŻĹ)
"""
import os, re, json, base64
from difflib import SequenceMatcher
from functools import lru_cache
try:
    import requests
except ImportError:
    requests = None


# ===== ŠľçŠíúŔžúŠ×É =====
def parse_docx(filepath):
    ext = os.path.splitext(filepath)[1].lower()
    if ext == '.txt':
        with open(filepath, 'r', encoding='utf-8') as f:
            return [l.strip() for l in f if l.strip()]
    import zipfile
    from xml.etree import ElementTree
    ns = '{http://schemas.openxmlformats.org/wordprocessingml/2006/main}'
    paragraphs = []
    with zipfile.ZipFile(filepath) as z:
        with z.open('word/document.xml') as f:
            tree = ElementTree.parse(f)
    for p in tree.iter(f'{ns}p'):
        texts = [t.text for t in p.iter(f'{ns}t') if t.text]
        line = ''.join(texts).strip()
        if line:
            paragraphs.append(line)
    return paragraphs


# ===== ŠľçŠťČŔžäŔîâňîľ =====
_RE_PUNCT = re.compile(r'[´╝îŃÇé´╝ü´╝č´╝Ť´╝ÜŃÇü\u201c\u201d\u2018\u2019´╝ł´╝ëŃÇÉŃÇĹŃÇŐŃÇőÔÇŽÔÇö┬Ě\s,.!?;:\'\"()\[\]{}\-]')
FILLER_WORDS = {'ňŚ»', 'ňĹâ', 'ňĽŐ', 'ňôŽ', 'ňĹó', 'ňÉž', 'ňśŤ', 'ňôł', 'ňÖó', 'Ŕ»Â',
                'ÚéúńŞ¬', 'ň░▒Šś»', 'šäÂňÉÄ', 'ň░▒Šś»Ŕ»┤', 'ň»╣ňÉž', 'ň»╣šÜä', 'Ŕ┐ÖńŞ¬'}
CN_NUM = {'0':'ÚŤÂ','1':'ńŞÇ','2':'ń║î','3':'ńŞë','4':'ňŤŤ','5':'ń║ö','6':'ňůş','7':'ńŞâ','8':'ňůź','9':'ń╣Ł'}
_RE_SENT_SPLIT = re.compile(r'(?<=[ŃÇé´╝ü´╝č´╝Ť\n])\s*')

def _norm(text):
    return _RE_PUNCT.sub('', text)

def _segment(text):
    return [c for c in text if c.strip()]

def _num_reading(text):
    result = re.sub(r'(\d{4})ň╣┤', lambda m: ''.join(CN_NUM.get(d,d) for d in m.group(1))+'ň╣┤', text)
    result = re.sub(r'(\d+)%', lambda m: 'šÖżňłćń╣ő'+''.join(CN_NUM.get(d,d) for d in m.group(1)), result)
    return re.sub(r'(\d+)', lambda m: ''.join(CN_NUM.get(d,d) for d in m.group(1)), result)

def _strip_fillers(text):
    """tokenš║žňüťšöĘŔ»ŹŔ┐çŠ╗Ą´╝Üń╗ÄŠľçŠťČńŞşšž╗ÚÖĄŠëÇŠťëňíźňůůŔ»Ź"""
    result = text
    for fw in sorted(FILLER_WORDS, key=len, reverse=True):
        result = result.replace(fw, '')
    return result

@lru_cache(maxsize=2048)
def _get_pinyin(text):
    """š╝ôňşśŠő╝Úč│ŔŻČŠŹóš╗ôŠ×ť"""
    try:
        from pypinyin import pinyin, Style
        return tuple(tuple(p) for p in pinyin(text, style=Style.TONE3, neutral_tone_with_five=True))
    except ImportError:
        return None

def _same_pinyin(a, b):
    """Ŕ»╗Úč│Š»öŔżâ´╝łňŞŽLRUš╝ôňşś´╝ë´╝ÜňşŚŠĽ░šŤŞňÉîńŞöŔ»╗Úč│ńŞÇŔç┤ŔžćńŞ║ňÉłŠá╝
    Šö»ŠîüńŞşŠľçňÉîÚč│ňşŚŃÇüŠĽ░ňşŚŔ»╗Úč│ŃÇüŔő▒Ŕ»şňĄžň░ĆňćÖ
    """
    a_c, b_c = _norm(a), _norm(b)
    if not a_c or not b_c:
        return False
    if a_c == b_c:
        return True
    if a_c.lower() == b_c.lower():
        return True
    a_n, b_n = _num_reading(a_c), _num_reading(b_c)
    if a_n == b_n:
        return True
    # š╝ôňşśŠő╝Úč│Š»öŔżâ
    pa = _get_pinyin(a_c)
    pb = _get_pinyin(b_c)
    if pa is not None and pb is not None:
        if pa == pb:
            return True
        pa_n = _get_pinyin(a_n)
        pb_n = _get_pinyin(b_n)
        if pa_n is not None and pb_n is not None and pa_n == pb_n:
            return True
    return False


# ===== ň»╣Š»öš«ŚŠ│Ľ´╝łňłćň▒éň»╣ÚŻÉ + ňŐáŠŁâCER´╝ë =====
def _align_chars(doc_chars, audio_chars, max_window=500):
    """ňşŚš║žň»╣ÚŻÉ´╝Üň»╣ńŞĄŠ«ÁŠľçŠťČňüÜ SequenceMatcher´╝îŔ┐öňŤ×ňĚ«ň╝éňłŚŔíĘ
    max_window: ŔÂůŔ┐çŠşĄÚĽ┐ň║ŽňłćŠ«ÁňĄäšÉćÚü┐ňůŹ O(n*m) šłćšéŞ
    """
    if len(doc_chars) + len(audio_chars) <= max_window:
        return _get_char_diffs(doc_chars, audio_chars)

    # ňłćŠ«ÁňĄäšÉć´╝ÜŠîë max_window/2 š¬ŚňĆúŠ╗ĹňŐĘ
    half = max_window // 2
    all_diffs = []
    di = ai = 0
    while di < len(doc_chars) or ai < len(audio_chars):
        d_end = min(di + half, len(doc_chars))
        a_end = min(ai + half, len(audio_chars))
        chunk_diffs = _get_char_diffs(doc_chars[di:d_end], audio_chars[ai:a_end])
        for d in chunk_diffs:
            d['_doc_offset'] = di
            d['_audio_offset'] = ai
        all_diffs.extend(chunk_diffs)
        di = d_end
        ai = a_end
    return all_diffs


def _get_char_diffs(doc_chars, audio_chars):
    """ňŹĽš¬ŚňĆúňćůšÜäňşŚš║žňĚ«ň╝éŠĆÉňĆľ"""
    matcher = SequenceMatcher(None, doc_chars, audio_chars)
    diffs = []
    for tag, i1, i2, j1, j2 in matcher.get_opcodes():
        if tag == 'equal':
            continue
        doc_frag = ''.join(doc_chars[i1:i2])
        audio_frag = ''.join(audio_chars[j1:j2])
        diffs.append({
            'tag': tag, 'doc_frag': doc_frag, 'audio_frag': audio_frag,
            'di1': i1, 'di2': i2, 'ai1': j1, 'ai2': j2
        })
    return diffs


def compare_texts(audio_text, doc_text):
    """ňłćň▒éň»╣Š»ö´╝ÜňĆąňłçňłć Ôćĺ ňĆąš║žň»╣ÚŻÉ Ôćĺ ňĆąňćůňşŚš║žš▓żń┐«
    Ŕ┐öňŤ×: (summary, diffs_list)
    """
    # ňĆąňłçňłć
    doc_sents = [s for s in _RE_SENT_SPLIT.split(doc_text) if s.strip()]
    audio_sents = [s for s in _RE_SENT_SPLIT.split(audio_text) if s.strip()]

    # ňŽéŠ×ťňĆąňĄ¬ň░Ĺ´╝łŠłľŠ▓íŠáçšé╣´╝ë´╝îÚÇÇňîľńŞ║ŠĽ┤Š«Áň»╣Š»ö
    if len(doc_sents) <= 1 and len(audio_sents) <= 1:
        return _compare_flat(audio_text, doc_text)

    # ňĆąš║žň»╣ÚŻÉ
    doc_sent_norms = [_norm(s) for s in doc_sents]
    audio_sent_norms = [_norm(s) for s in audio_sents]
    sent_matcher = SequenceMatcher(None, doc_sent_norms, audio_sent_norms)

    all_diffs = []
    sub_chars = del_chars = ins_chars = 0

    for tag, i1, i2, j1, j2 in sent_matcher.get_opcodes():
        if tag == 'equal':
            continue

        # ň»╣ńŞŹńŞÇŔç┤šÜäňĆąš╗ä´╝îňüÜňşŚš║žš▓żń┐«
        doc_block = ''.join(doc_sents[i1:i2])
        audio_block = ''.join(audio_sents[j1:j2])
        d_chars = _segment(_norm(doc_block))
        a_chars = _segment(_norm(audio_block))

        char_diffs = _align_chars(d_chars, a_chars)
        for cd in char_diffs:
            d_frag = cd['doc_frag']
            a_frag = cd['audio_frag']
            ct = cd['tag']

            # tokenš║žňíźňůůŔ»ŹŔ┐çŠ╗Ą
            if ct == 'insert':
                cleaned = _strip_fillers(a_frag)
                if not cleaned.strip():
                    continue
            if ct == 'delete':
                cleaned = _strip_fillers(d_frag)
                if not cleaned.strip():
                    continue
            if ct == 'replace':
                d_clean = _strip_fillers(d_frag)
                a_clean = _strip_fillers(a_frag)
                if not d_clean.strip() and not a_clean.strip():
                    continue
                if _same_pinyin(d_frag, a_frag):
                    continue
            if not d_frag.strip() and not a_frag.strip():
                continue

            dtype = 'Ŕ»»Ŕ»╗' if ct == 'replace' else ('Š╝ĆŔ»╗' if ct == 'delete' else 'ňĄÜŔ»╗')
            if ct == 'replace':
                all_diffs.append('[%s] ňÄčŠľç: %s Ôćĺ ňŻĽÚč│: %s' % (dtype, d_frag, a_frag))
                sub_chars += max(len(d_frag), len(a_frag))
            elif ct == 'delete':
                all_diffs.append('[%s] %s' % (dtype, d_frag))
                del_chars += len(d_frag)
            else:
                all_diffs.append('[%s] %s' % (dtype, a_frag))
                ins_chars += len(a_frag)

    n_mis = sum(1 for d in all_diffs if d.startswith('[Ŕ»»Ŕ»╗'))
    n_miss = sum(1 for d in all_diffs if d.startswith('[Š╝ĆŔ»╗'))
    n_extra = sum(1 for d in all_diffs if d.startswith('[ňĄÜŔ»╗'))

    # ňŐáŠŁâ CER´╝Üsubstitution 1.0, deletion 1.0, insertion 0.5
    total = max(len(_norm(doc_text)), 1)
    weighted_errors = sub_chars * 1.0 + del_chars * 1.0 + ins_chars * 0.5
    accuracy = max(0, (1 - weighted_errors / total) * 100)
    cer = min(100, weighted_errors / total * 100)

    summary = 'ňů▒%dňĄäňĚ«ň╝é´╝Ü%dňĄäŔ»»Ŕ»╗´╝î%dňĄäŠ╝ĆŔ»╗´╝î%dňĄäňĄÜŔ»╗\nňşŚňçćší«šÄç %.1f%% (CER %.1f%%)' % (
        len(all_diffs), n_mis, n_miss, n_extra, accuracy, cer)
    return summary, all_diffs


def _compare_flat(audio_text, doc_text):
    """ÚÇÇňîľšÜäŠĽ┤Š«ÁňşŚš║žň»╣Š»ö´╝łŠŚáňĆąňłçňłćŠŚÂńŻ┐šöĘ´╝ë"""
    audio_norm = _norm(audio_text)
    doc_norm = _norm(doc_text)
    audio_words = _segment(audio_norm)
    doc_words = _segment(doc_norm)

    char_diffs = _align_chars(doc_words, audio_words)
    diffs = []
    sub_chars = del_chars = ins_chars = 0

    for cd in char_diffs:
        d_frag = cd['doc_frag']
        a_frag = cd['audio_frag']
        ct = cd['tag']

        if ct == 'insert':
            cleaned = _strip_fillers(a_frag)
            if not cleaned.strip():
                continue
        if ct == 'delete':
            cleaned = _strip_fillers(d_frag)
            if not cleaned.strip():
                continue
        if ct == 'replace':
            if _same_pinyin(d_frag, a_frag):
                continue
        if not d_frag.strip() and not a_frag.strip():
            continue

        dtype = 'Ŕ»»Ŕ»╗' if ct == 'replace' else ('Š╝ĆŔ»╗' if ct == 'delete' else 'ňĄÜŔ»╗')
        if ct == 'replace':
            diffs.append('[%s] ňÄčŠľç: %s Ôćĺ ňŻĽÚč│: %s' % (dtype, d_frag, a_frag))
            sub_chars += max(len(d_frag), len(a_frag))
        elif ct == 'delete':
            diffs.append('[%s] %s' % (dtype, d_frag))
            del_chars += len(d_frag)
        else:
            diffs.append('[%s] %s' % (dtype, a_frag))
            ins_chars += len(a_frag)

    n_mis = sum(1 for d in diffs if d.startswith('[Ŕ»»Ŕ»╗'))
    n_miss = sum(1 for d in diffs if d.startswith('[Š╝ĆŔ»╗'))
    n_extra = sum(1 for d in diffs if d.startswith('[ňĄÜŔ»╗'))
    total = max(len(doc_norm), 1)
    weighted_errors = sub_chars * 1.0 + del_chars * 1.0 + ins_chars * 0.5
    accuracy = max(0, (1 - weighted_errors / total) * 100)
    cer = min(100, weighted_errors / total * 100)

    summary = 'ňů▒%dňĄäňĚ«ň╝é´╝Ü%dňĄäŔ»»Ŕ»╗´╝î%dňĄäŠ╝ĆŔ»╗´╝î%dňĄäňĄÜŔ»╗\nňşŚňçćší«šÄç %.1f%% (CER %.1f%%)' % (
        len(diffs), n_mis, n_miss, n_extra, accuracy, cer)
    return summary, diffs


