        f.write('ŠľçŠíúŠľçń╗Â: %s\n\n' % os.path.basename(doc_path))
        f.write(result_text)
        f.write('\n\n' + '=' * 50 + '\n')
        f.write('ň«îŠĽ┤ŔŻČňćÖŠľçŠťČ:\n')
